suspend fun loadJobDetail(jobId: String): JobDetailData = coroutineScope {
    val jobDeferred = async { jobRepository.getJob(jobId) }
    val savedDeferred = async { savedJobRepository.isSaved(jobId) }
    val appliedDeferred = async { applicationRepository.getStatus(jobId) }

    val job = jobDeferred.await()
    val company = companyRepository.getCompany(job.companyId)

    JobDetailData(
        job = job,
        company = company,
        isSaved = savedDeferred.await(),
        applicationStatus = appliedDeferred.await()
    )
}

fun loadHome() {
    viewModelScope.launch {
        supervisorScope {
            launch { loadProfile() }
            launch { loadRecommendations() }
            launch { loadRecentSearches() }
            launch { loadUnreadCount() }
        }
    }
}

private var streamingJob: Job? = null

fun changeFilter(filter: JobFilter) {
    streamingJob?.cancel()
    streamingJob = viewModelScope.launch {
        supervisorScope {
            launch { collectSkillJobs(filter) }
            launch { collectNearbyJobs(filter) }
            launch { collectRecentJobs(filter) }
        }
    }
}

suspend fun processDocument(image: Bitmap) =
    withContext(Dispatchers.Default) {
        val processed = preprocessImage(image)
        coroutineScope {
            val mrz = async { recognizeMrz(processed) }
            val face = async { cropFace(processed) }
            DocumentResult(mrz.await(), face.await())
        }
    }

val uploadLimit = Semaphore(3)

suspend fun uploadAll(files: List<File>) = coroutineScope {
    files.map { file ->
        async {
            uploadLimit.withPermit { upload(file) }
        }
    }.awaitAll()
}

private val refreshMutex = Mutex()

suspend fun refreshIfNeeded(expiredToken: String): String =
    refreshMutex.withLock {
        val current = tokenStorage.accessToken()
        if (current != expiredToken) return current

        val newToken = authApi.refreshToken()
        tokenStorage.save(newToken)
        newToken
    }

